import React, { useState, useContext } from 'react';
import { taxasIRT } from '../data/mockData';
import { AppContext } from '../App';
import { Colaborador } from '../types';

const Processamento: React.FC = () => {
  const { empresa, colaboradores } = useContext(AppContext);
  const ativos = colaboradores.filter(c => c.status === 'Ativo');

  const currentYear = new Date().getFullYear();
  const currentDay = new Date().getDate();
  const [selectedMonth, setSelectedMonth] = useState('Janeiro');
  const [selectedYear, setSelectedYear] = useState(currentYear.toString());
  const [selectedDay, setSelectedDay] = useState(currentDay.toString());

  const [showFormModal, setShowFormModal] = useState(false);
  const [showReceiptModal, setShowReceiptModal] = useState(false);
  const [selectedColab, setSelectedColab] = useState<Colaborador | null>(null);

  // Form states
  const [formSalario, setFormSalario] = useState(0);
  const [formFaltas, setFormFaltas] = useState(0);
  const [formAlimentacao, setFormAlimentacao] = useState(0);
  const [formTransporte, setFormTransporte] = useState(0);
  const [formFerias, setFormFerias] = useState(0);
  const [outrosSubsidios, setOutrosSubsidios] = useState<{nome: string, valor: number}[]>([]);
  const [formHorasExtra, setFormHorasExtra] = useState(0);
  const [formBonus, setFormBonus] = useState(0);

  const calcularIRT = (baseSujeitaIRT: number) => {
    const escalao = taxasIRT.find(t => baseSujeitaIRT >= t.minimo && baseSujeitaIRT <= t.maximo);
    if (!escalao) return 0;
    const calc = ((baseSujeitaIRT - escalao.minimo) * (escalao.taxa / 100)) + escalao.parcelaAbt;
    return calc > 0 ? calc : 0;
  };

  const handleStartProcessar = (colab: Colaborador) => {
    setSelectedColab(colab);
    setFormSalario(colab.salarioBase || 0);
    setFormFaltas(0);
    setFormAlimentacao(30000);
    setFormTransporte(20000);
    setFormFerias(0);
    setOutrosSubsidios([]);
    setFormHorasExtra(0);
    setFormBonus(0);
    setShowFormModal(true);
  };

  const handleAddSubsidio = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const value = e.target.value;
    if (value === 'Outro') {
      const nome = prompt('Digite o nome do subsídio:');
      if (nome) {
        setOutrosSubsidios([...outrosSubsidios, { nome, valor: 0 }]);
      }
    } else if (value !== '') {
      setOutrosSubsidios([...outrosSubsidios, { nome: value, valor: 0 }]);
    }
    e.target.value = ''; // Reset select
  };

  const handleUpdateSubsidioValor = (index: number, valor: number) => {
    const newSubsidios = [...outrosSubsidios];
    newSubsidios[index].valor = valor;
    setOutrosSubsidios(newSubsidios);
  };

  const removeOutroSubsidio = (index: number) => {
    setOutrosSubsidios(outrosSubsidios.filter((_, i) => i !== index));
  };

  const handleConfirmForm = (e: React.FormEvent) => {
    e.preventDefault();
    setShowFormModal(false);
    setShowReceiptModal(true);
  };

  const currentCalc = () => {
    const totalOutros = outrosSubsidios.reduce((acc, curr) => acc + curr.valor, 0);
    const totalBruto = formSalario + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus;
    const baseSalarioLiquidoFaltas = formSalario - formFaltas;

    const taxaINSS = empresa?.taxaINSS || 3;
    const valorINSS = baseSalarioLiquidoFaltas * (taxaINSS / 100);
    const baseIRT = baseSalarioLiquidoFaltas - valorINSS + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus; 
    const valorIRT = calcularIRT(baseIRT);

    const totalDescontos = valorINSS + valorIRT + formFaltas;
    const salarioLiquido = totalBruto - totalDescontos;

    return { totalBruto, valorINSS, valorIRT, totalDescontos, salarioLiquido };
  };

  const handleImprimir = () => {
    window.print();
  };

  const handleGuardar = () => {
    const element = document.getElementById('recibo-para-impressao');
    if (!element) return;

    // @ts-ignore
    const opt = {
      margin: 5,
      filename: `Recibo_${selectedColab?.nome.replace(/ /g, '_')}_${selectedMonth}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    // @ts-ignore
    window.html2pdf().from(element).set(opt).save();
  };

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-black tracking-tight">Processamento de Salários</h2>
          <p className="text-slate-500 text-sm">Gere a folha de pagamento do período selecionado.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Mês</label>
          <select value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="w-full bg-transparent border-none p-0 focus:ring-0 font-bold text-slate-800 dark:text-white">
            {['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'].map(m => (
              <option key={m} value={m}>{m}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Ano</label>
          <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)} className="w-full bg-transparent border-none p-0 focus:ring-0 font-bold text-slate-800 dark:text-white">
            {['2024', '2025', '2026', '2027'].map(y => (
              <option key={y} value={y}>{y}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Dia</label>
          <input type="number" min="1" max="31" value={selectedDay} onChange={e => setSelectedDay(e.target.value)} className="w-full bg-transparent border-none p-0 focus:ring-0 font-bold text-slate-800 dark:text-white" />
        </div>
        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 flex items-center justify-between">
          <div>
            <p className="text-[10px] font-bold text-slate-400 uppercase">Status</p>
            <p className="text-sm font-bold text-emerald-500 uppercase">Aberto</p>
          </div>
          <span className="material-symbols-outlined text-slate-300">event_available</span>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
              <tr>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase">Colaborador</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase text-right">Salário Base</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase text-center">Ação</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {ativos.map(c => (
                <tr key={c.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                  <td className="p-4">
                    <div className="flex items-center gap-3">
                      <div className="size-10 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold text-xs uppercase">{c.nome.substring(0, 2)}</div>
                      <div>
                        <p className="text-sm font-semibold">{c.nome}</p>
                        <p className="text-xs text-slate-500">{c.cargo}</p>
                      </div>
                    </div>
                  </td>
                  <td className="p-4 text-right font-medium text-sm">{c.salarioBase.toLocaleString()} Kz</td>
                  <td className="p-4 text-center">
                    <button onClick={() => handleStartProcessar(c)} className="text-primary border border-primary/20 hover:bg-primary/10 px-4 py-1.5 rounded-lg text-xs font-bold transition-colors">Processar</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showFormModal && selectedColab && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[60] p-4 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 rounded-xl max-w-lg w-full max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b border-slate-200 dark:border-slate-800 flex items-start justify-between">
              <div>
                <h2 className="font-black text-xl text-slate-900 dark:text-white uppercase tracking-wider">Validar Processamento</h2>
                <div className="text-slate-500 text-sm font-medium">{selectedColab.nome}</div>
              </div>
              <button onClick={() => setShowFormModal(false)} className="p-2 hover:bg-slate-100 rounded-lg transition-colors"><span className="material-symbols-outlined">close</span></button>
            </div>
            <form onSubmit={handleConfirmForm} className="p-6 space-y-5">
              <div className="space-y-1.5">
                <label className="text-sm font-bold text-slate-700 dark:text-slate-300">Salário Base (Kz)</label>
                <input required type="text" value={formSalario ? formSalario.toLocaleString('pt-AO') : ''} onChange={e => setFormSalario(Number(e.target.value.replace(/\D/g, '')))} className="w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg font-black text-primary text-lg" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5"><label className="text-sm font-bold text-slate-700 dark:text-slate-300">Subs. Alimentação</label><input type="number" value={formAlimentacao === 0 ? '' : formAlimentacao} onChange={e => setFormAlimentacao(Number(e.target.value))} className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-sm" /></div>
                <div className="space-y-1.5"><label className="text-sm font-bold text-slate-700 dark:text-slate-300">Subs. Transporte</label><input type="number" value={formTransporte === 0 ? '' : formTransporte} onChange={e => setFormTransporte(Number(e.target.value))} className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-sm" /></div>
              </div>

              {/* Dynamic Subsidies */}
              <div className="space-y-4 pt-2">
                <div className="flex items-center justify-between border-b pb-2">
                   <label className="text-sm font-black text-primary uppercase tracking-wider flex items-center gap-2">
                     <span className="material-symbols-outlined text-base">add_circle</span>
                     Outros Subsídios
                   </label>
                   <select 
                     onChange={handleAddSubsidio}
                     className="text-xs bg-slate-100 dark:bg-slate-800 border-none rounded-lg py-1 px-3 font-bold text-slate-600 dark:text-slate-300 cursor-pointer hover:bg-slate-200"
                   >
                     <option value="">+ Adicionar</option>
                     <option value="Subsídio de Chefia">Subsídio de Chefia</option>
                     <option value="Subsídio de Disponibilidade">Subsídio de Disponibilidade</option>
                     <option value="Subsídio de Instalação">Subsídio de Instalação</option>
                     <option value="Gratificação">Gratificação</option>
                     <option value="Outro">Outro...</option>
                   </select>
                </div>

                <div className="space-y-3">
                  {outrosSubsidios.map((s, idx) => (
                    <div key={idx} className="grid grid-cols-1 gap-1.5 animate-in fade-in slide-in-from-top-2 duration-200">
                      <div className="flex items-center justify-between">
                        <label className="text-sm font-bold text-slate-700 dark:text-slate-300">{s.nome}</label>
                        <button type="button" onClick={() => removeOutroSubsidio(idx)} className="text-red-500 hover:bg-red-50 p-1 rounded-md transition-colors"><span className="material-symbols-outlined text-sm">close</span></button>
                      </div>
                      <input 
                        type="number" 
                        value={s.valor === 0 ? '' : s.valor} 
                        onChange={e => handleUpdateSubsidioValor(idx, Number(e.target.value))} 
                        placeholder="0"
                        className="w-full px-4 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-sm font-bold text-slate-900 dark:text-white" 
                      />
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 border-t pt-2">
                <div className="space-y-1.5"><label className="text-sm font-bold text-green-700">Horas Extra</label><input type="number" value={formHorasExtra === 0 ? '' : formHorasExtra} onChange={e => setFormHorasExtra(Number(e.target.value))} className="w-full px-4 py-2 bg-green-50/30 border border-green-200 rounded-lg text-sm" /></div>
                <div className="space-y-1.5"><label className="text-sm font-bold text-green-700">Bónus/Prémio</label><input type="number" value={formBonus === 0 ? '' : formBonus} onChange={e => setFormBonus(Number(e.target.value))} className="w-full px-4 py-2 bg-green-50/30 border border-green-200 rounded-lg text-sm" /></div>
              </div>

              <div className="space-y-1.5 border-t pt-4">
                <label className="text-sm font-bold text-red-600">Faltas (Valor a Descontar)</label>
                <input type="number" value={formFaltas === 0 ? '' : formFaltas} onChange={e => setFormFaltas(Number(e.target.value))} className="w-full px-4 py-2 bg-red-50/30 border border-red-200 rounded-lg text-sm text-red-700 font-bold" />
              </div>

              <button type="submit" className="w-full mt-4 py-3.5 bg-primary text-white rounded-lg font-black hover:bg-primary/90 flex items-center justify-center gap-3 shadow-xl shadow-primary/20 transition-all uppercase tracking-widest text-sm">
                <span className="material-symbols-outlined">payments</span>
                Confirmar Processamento
              </button>
            </form>
          </div>
        </div>
      )}

      {showReceiptModal && selectedColab && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-[70] p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl max-w-[210mm] w-full max-h-[95vh] overflow-y-auto shadow-2xl relative">
            <style>{`
              @media print {
                @page { size: portrait; margin: 10mm; }
                body * { visibility: hidden; }
                #recibo-para-impressao, #recibo-para-impressao * { visibility: visible; }
                #recibo-para-impressao { 
                  position: absolute; 
                  left: 0; 
                  top: 0; 
                  width: 100%; 
                  height: auto;
                  margin: 0;
                  padding: 10mm;
                  box-shadow: none;
                }
                .no-print { display: none !important; }
              }
            `}</style>

            <div className="p-10 bg-white text-slate-900" id="recibo-para-impressao" style={{ boxSizing: 'border-box' }}>
              {/* Header */}
              <div className="flex justify-between items-start border-b-2 border-slate-900 pb-4 mb-6">
                <div>
                  <h1 className="text-xl font-black text-slate-900 uppercase tracking-tight">{empresa?.nome || 'EMPRESA'}</h1>
                  <p className="text-[9px] font-bold text-slate-500 mt-1">NIF: {empresa?.nif || '-'}</p>
                  <p className="text-[8px] text-slate-400 max-w-[300px] leading-tight mt-1">{empresa?.endereco || ''}</p>
                </div>
                <div className="text-right">
                  <h2 className="text-base font-black text-slate-900 border-2 border-slate-900 px-4 py-1 inline-block">RECIBO DE SALÁRIO</h2>
                  <div className="mt-2 text-right">
                    <p className="text-[10px] font-black uppercase">Período: {selectedMonth} / {selectedYear}</p>
                    <p className="text-[8px] text-slate-500">Data de Emissão: {selectedDay}/{selectedMonth}/{selectedYear}</p>
                  </div>
                </div>
              </div>

              {/* Info Grid */}
              <div className="grid grid-cols-2 gap-6 mb-6">
                <div className="border border-slate-200 p-4 rounded bg-slate-50/50">
                  <h3 className="text-[9px] font-black text-slate-400 mb-2 uppercase border-b pb-1">Colaborador</h3>
                  <p className="text-xs font-black truncate">{selectedColab.nome}</p>
                  <div className="grid grid-cols-2 gap-2 mt-2">
                    <div>
                      <p className="text-[8px] text-slate-500 uppercase">ID No.</p>
                      <p className="text-[10px] font-bold">{selectedColab.numeroColaborador || '-'}</p>
                    </div>
                    <div>
                      <p className="text-[8px] text-slate-500 uppercase">Cargo</p>
                      <p className="text-[10px] font-bold">{selectedColab.cargo}</p>
                    </div>
                  </div>
                </div>
                <div className="border border-slate-200 p-4 rounded bg-slate-50/50">
                  <h3 className="text-[9px] font-black text-slate-400 mb-2 uppercase border-b pb-1">Pagamento</h3>
                  <div className="grid grid-cols-1 gap-1">
                    <p className="text-[10px]"><strong>NIF:</strong> {selectedColab.nif}</p>
                    <p className="text-[10px]"><strong>INSS:</strong> {selectedColab.inss || '-'}</p>
                    <div className="mt-1 p-1.5 bg-white border border-slate-200 text-center">
                       <p className="text-[7px] text-slate-400 font-bold uppercase">IBAN PARA DEPÓSITO</p>
                       <p className="text-xs font-black text-primary">{selectedColab.iban || '-'}</p>
                    </div>
                  </div>
                </div>
              </div>

              {/* Table */}
              <table className="w-full text-xs mb-6 border-collapse">
                <thead>
                  <tr className="bg-slate-900 text-white font-black text-[9px] uppercase">
                    <th className="p-2 text-left border border-slate-900">Descrição dos Rendimentos e Descontos</th>
                    <th className="p-2 text-right border border-slate-900 w-32">Valor (Kz)</th>
                  </tr>
                </thead>
                <tbody>
                  <tr className="border border-slate-200 font-bold"><td className="p-2">Salário Base</td><td className="p-2 text-right">{formSalario.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                  {formAlimentacao > 0 && <tr className="border border-slate-200"><td className="p-2">Subsídio de Alimentação</td><td className="p-2 text-right">{formAlimentacao.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                  {formTransporte > 0 && <tr className="border border-slate-200"><td className="p-2">Subsídio de Transporte</td><td className="p-2 text-right">{formTransporte.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                  {outrosSubsidios.map((s, idx) => (
                    <tr key={idx} className="border border-slate-200"><td className="p-2">{s.nome}</td><td className="p-2 text-right">{s.valor.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                  ))}
                  {formHorasExtra > 0 && <tr className="border border-slate-200"><td className="p-2">Horas Extra</td><td className="p-2 text-right">{formHorasExtra.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                  {formBonus > 0 && <tr className="border border-slate-200"><td className="p-2">Bónus / Gratificações</td><td className="p-2 text-right">{formBonus.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}

                  <tr className="bg-slate-50 font-black"><td className="p-2 text-right uppercase text-[9px]">Total Rendimentos Brutos</td><td className="p-2 text-right border-t border-slate-900">{currentCalc().totalBruto.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>

                  <tr className="bg-white"><td colSpan={2} className="p-2"></td></tr>

                  <tr className="border border-slate-200 text-slate-500 italic"><td className="p-2">Desconto Segurança Social ({empresa?.taxaINSS || 3}%)</td><td className="p-2 text-right">- {currentCalc().valorINSS.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                  <tr className="border border-slate-200 text-slate-500 italic"><td className="p-2">Desconto Imposto (IRT)</td><td className="p-2 text-right">- {currentCalc().valorIRT.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                  {formFaltas > 0 && <tr className="border border-slate-200 text-red-500 italic"><td className="p-2">Desconto por Faltas</td><td className="p-2 text-right">- {formFaltas.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                </tbody>
              </table>

              {/* Total Box */}
              <div className="flex justify-end mb-10">
                <div className="bg-slate-900 text-white p-4 rounded-lg w-full max-w-[300px] flex justify-between items-center ring-4 ring-slate-100">
                  <span className="text-[10px] font-black uppercase tracking-widest">Valor Líquido a Receber</span>
                  <span className="text-xl font-black">{currentCalc().salarioLiquido.toLocaleString('pt-AO', { minimumFractionDigits: 2 })} Kz</span>
                </div>
              </div>

              {/* Footer */}
              <div className="mt-auto pt-10 border-t border-slate-100 text-center">
                <p className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">Recibo processado pelo software de gestão SALYA</p>
                <div className="flex justify-center gap-10 mt-2">
                   <p className="text-[7px] text-slate-300">ID: {Date.now()}</p>
                   <p className="text-[7px] text-slate-300">Pág: 01/01</p>
                </div>
              </div>
            </div>

            <div className="p-6 bg-slate-50 border-t flex gap-4 no-print sticky bottom-0 rounded-b-xl z-10">
              <button onClick={handleGuardar} className="flex-1 py-3 bg-primary text-white rounded-lg font-black flex items-center justify-center gap-2 shadow-lg shadow-primary/20"><span className="material-symbols-outlined">description</span> GUARDAR PDF</button>
              <button onClick={handleImprimir} className="flex-1 py-3 bg-white text-slate-900 border border-slate-300 rounded-lg font-black flex items-center justify-center gap-2 hover:bg-slate-100 transition-colors"><span className="material-symbols-outlined">print</span> IMPRIMIR</button>
              <button onClick={() => setShowReceiptModal(false)} className="px-8 py-3 bg-slate-200 text-slate-600 rounded-lg font-bold hover:bg-slate-300 transition-colors">FECHAR</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Processamento;
